#define eps 1e-9
#define MID ((l+r)>>1)
#define lson (o<<1)
#define rson (o<<1|1)
//clear the array
#define cla(a) memset(a,0,sizeof(a))
#define clb(a) memset(a,INF,sizeof(a))
#define clc(a) memset(a,-1,sizeof(a))




using namespace std;

const ull mod=998244353;
const int maxn =100010;


ull A[maxn],B[maxn],C[maxn],base[maxn];
map<ull , int > MP;
int n;

inline void init()
{
	base[0]=1;
	for (int i=1;i<=n;i++)
		base[i]=base[i-1]*mod;

}
int ans=mod;

//main
int main()
{
	//freopen("Untitled 3.txt.in","r",stdin);
	//freopen("Untitled 3.txt.out","w",stdout);
	cin>>n;
	init();
	for (int i=1;i<=n;i++)
	{
		cin>>A[i];
		A[i]=A[i-1]*mod+A[i];
	}
	for (int i=1;i<=n;i++)
	{
		cin>>B[i];
		B[i]=B[i-1]*mod+B[i];
	}
	for (int i=1;i<=n;i++)
		{
			cin>>C[i];
			C[i]=C[i-1]*mod+C[i];
		}
	for (int i=0;i<n;i++)
	{
		ull cur=(A[n]-A[i]*base[n-i])*base[i]+A[i];
		MP[cur]=i;//A左移动i位
	}
	for (int i=0;i<n;i++)
	{
		ull cur=(B[n]-B[i]*base[n-i])*base[i]+B[i];//B左移动n位
		if (MP.count(C[n]-cur))
			ans=min(ans,MP[C[n]-cur]+i);

	}
	cout<<((ans==mod)?-1:ans)<<endl;
	return 0;
}



