void GetNext()
{
	memset(nnext,0,sizeof(nnext));
	int k = strlen(p);
    nnext[0]=-1;
    int i = 0;
	int j = -1;
    while(i<k)
    {
        if (j==-1||p[i]==p[j])
        {
            ++i;
            ++j;
            nnext[i] = j;
        }
        else
            j = nnext[j];
    }
	for(int i=0;i<k;++i)
	++book[nnext[i]];
}

int main()
