<h3>
E - Spy Syndrome 2
</h3>
<p style="text-indent:2em">
    给你一个长度为N的文本串，这个文本串是由一堆 单词拆分开之后每个单词变小写并翻转的来的，现在给你这个长度为N的字符串，还给你他的原来的组成成分，你要还原这句话，其中有的单词可能是多余的。
</p>

<p style="text-indent:2em">
    其实还是字典树的裸题，不过既然它翻转过来了，我们就直接倒序建立字典树，倒序跑Trie匹配，最后再将单词倒序输出即可。
</p>

By 本场Rank2同学

```C++
#include<bits/stdc++.h>
using namespace std;
//既有单词建树、reverse原、break原、dfs、倒序output
const int maxn=1e5+5;
const int maxx=1e6+5;
int tr[maxx][30],num[maxx],n,m,tot,dp[maxn];
string s[maxn];
string a;
vector<int>v;
void build_trie(string& s,int No) {
	int p=0;
	for (auto &j : s) {
		int c;
		if(j>='a'&&j<='z')c=j-'a';
		else if(j>='A'&&j<='Z')c=j-'A';
		if(!tr[p][c]) tr[p][c] = ++tot;
		p=tr[p][c];
	}
	num[p]=No;
}
void find(int t){
	int p=0;
	for(int i=t;i<n;i++){
		int c=a[i]-'a';
		if(!tr[p][c])return;
		p=tr[p][c];
		if(num[p])dp[i+1]=num[p];//mark the position
	}
}
void dfs(int k=n){//corret the order
	if(!k)return;
	int tmp=s[dp[k]].size();
	v.push_back(dp[k]);
	dfs(k-tmp);
}
int main(){
	scanf("%d",&n);
	cin>>a;
	scanf("%d",&m);
	for(int i=1;i<=m;i++){
		cin>>s[i];
		build_trie(s[i],i); 
	}
	reverse(a.begin(),a.end());
	find(0);
	for(int i=1;i<=n;i++){
		if(!dp[i])continue;
		find(i);
	}
	dfs();
//	cout<<"ok"<<endl;
	for(auto &r:v)cout<<s[r]<<" ";
	cout<<endl;
  	return 0;	
} 
```

