<h3>
G - Test 
</h3>

<p style="text-indent: 2em">
给你三个字符串，找⼀个字符串(它的⼦串含有以上三个字符串)，输出此字符串的最小⻓度。
</p>
<p style="text-indent: 2em">
    显然有$3!$种拼接顺序，我们直接暴力枚举一下拼接顺序。（next_permutation)。因为要求最小长度，我们自然希望拼接时能尽量把重叠部分合并。那我们自然就希望后一个串的前缀和前一个串的后缀能尽可能多地重叠！那么用KMP/Z拼接的思路就非常明确了。
</p>

一鱼两吃,Z-algorithm:

```C++
int f[maxn];
string S[4];
int ord[3]={0,1,2};
int ans=maxlongint;
//z-algorithm
inline string skr(string a,string b)
{
	string T=a+'$'+b;//merge a & b
	int n=a.length();
	int m=b.length();
	int Len=n+m+1;
	f[0]=Len;
	int j=1,k;
	for (int i=1;i<Len;i=k)
	{
		if (j<i) j=i;
		while (T[j-i]==T[j] && j<Len)
			j++;
		f[i]=j-i;
		k=i+1;
		while (k+f[k-i]<j) k++;
	}
	int Lim=m+1;
	for (int i=n+1;i<Len;i++)
	{
		if(f[i]==n)	return b;
		if (i+f[i]>=Len){
			Lim=min(Lim,i-n);break;
		}
	}
	string cur;
	cur=b.substr(0,Lim-1)+a;
	return cur;
}
//main
int main()
{
	cin>>S[0]>>S[1]>>S[2];
	do {
		ans=min(ans,(int)skr(skr(S[ord[0]],S[ord[1]]),S[ord[2]]).length());
	}while (next_permutation(ord,ord+3));
	//暴力枚举三个串链接的顺序
	cout<<ans<<endl;
	return 0;
}

```

KMP:

```C++
int f[maxn];
string S[4];
int ord[3]={0,1,2};
int ans=maxlongint;
inline string skr(string a,string b)
{
	string T=a+'$'+b;//merge a & b
	int n=a.length();
	int m=b.length();
	int Len=n+m+1;
	//int j=-1;
	f[0]=-1;
	int j=-1;
	for(int i=1;i<Len;i++)
		{
			while (j!=-1 && T[j+1]!=T[i])
					j=f[j];
			if(T[i]==T[j+1])
					j++;
			f[i]=j;
		}//找next数组
	for (int i=n+1;i<Len;i++)
		if (f[i]==n-1) return b;//a是b的子串
	string cur=b.substr(0,m-1-f[Len-1])+a;//b减去a的一部分前缀+a
	return cur;
}
//main
int main()
{

	cin>>S[0]>>S[1]>>S[2];
	do {
		ans=min(ans,(int)skr(skr(S[ord[0]],S[ord[1]]),S[ord[2]]).length());
	}while (next_permutation(ord,ord+3));
	//暴力枚举三个串链接的顺序
	cout<<ans<<endl;
	return 0;
}
```
